import{_ as i,o as a,c as t,ag as r}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"CareLite","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/120_applications/carelite.md","filePath":"10_core/40_service_apps/120_applications/carelite.md"}'),o={name:"10_core/40_service_apps/120_applications/carelite.md"};function l(s,e,n,c,h,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="carelite" tabindex="-1">CareLite <a class="header-anchor" href="#carelite" aria-label="Permalink to &quot;CareLite&quot;">​</a></h1><p>CareLite is the planned lightweight care tracker for Mom inside the QiAccess personal system.</p><p>It is meant to stay simple, fast, and usable under caregiver pressure.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>CareLite should provide a stripped-down care workflow for everyday use:</p><ul><li>quick status checks</li><li>simple medication tracking</li><li>short notes</li><li>basic observations</li><li>lightweight reminders or routines</li></ul><h2 id="relationship-to-qiaccess" tabindex="-1">Relationship To QiAccess <a class="header-anchor" href="#relationship-to-qiaccess" aria-label="Permalink to &quot;Relationship To QiAccess&quot;">​</a></h2><p>QiAccess should act as the launch and coordination layer.</p><p>CareLite should open as its own focused app when the task is direct day-to-day care tracking rather than system navigation or documentation.</p><h2 id="product-direction" tabindex="-1">Product Direction <a class="header-anchor" href="#product-direction" aria-label="Permalink to &quot;Product Direction&quot;">​</a></h2><p>CareLite should be lighter than a full care-management platform.</p><p>The target is:</p><ul><li>fewer screens</li><li>faster entry</li><li>less setup burden</li><li>cleaner daily use on phone</li></ul><p>It should not start as a heavy clinical charting system.</p><h2 id="mvp-direction" tabindex="-1">MVP Direction <a class="header-anchor" href="#mvp-direction" aria-label="Permalink to &quot;MVP Direction&quot;">​</a></h2><p>The first version should focus on:</p><ol><li>patient summary</li><li>medication checklist or confirmations</li><li>quick care notes</li><li>symptoms or observations</li><li>simple day view</li><li>exportable history if needed</li></ol><h2 id="starting-workflows" tabindex="-1">Starting Workflows <a class="header-anchor" href="#starting-workflows" aria-label="Permalink to &quot;Starting Workflows&quot;">​</a></h2><h3 id="daily-use" tabindex="-1">Daily use <a class="header-anchor" href="#daily-use" aria-label="Permalink to &quot;Daily use&quot;">​</a></h3><ol><li>Open CareLite from QiAccess.</li><li>Check today&#39;s care items.</li><li>Confirm meds or routine tasks.</li><li>Add a short note or observation.</li><li>Review recent history if something changes.</li></ol><h2 id="relationship-to-momscare" tabindex="-1">Relationship To MomsCare <a class="header-anchor" href="#relationship-to-momscare" aria-label="Permalink to &quot;Relationship To MomsCare&quot;">​</a></h2><p>CareLite should remain the simple version.</p><p>If a fuller caregiver platform already exists elsewhere, keep CareLite focused on the small everyday workflow instead of cloning a bigger app.</p><h2 id="initial-build-rule" tabindex="-1">Initial Build Rule <a class="header-anchor" href="#initial-build-rule" aria-label="Permalink to &quot;Initial Build Rule&quot;">​</a></h2><p>Optimize for low-friction caregiver use.</p><p>If a feature makes the daily workflow slower, it probably does not belong in the first version.</p>',26)])])}const m=i(o,[["render",l]]);export{u as __pageData,m as default};
